let showPass = () =>{
   btnShowPassword.classlist.toggle("active");
}
let Autorization = (props) =>{
   btnShowPassword = React.createRef();
   return(
      <div className="autorization">
         <input type="text" className = "name" placeholder="Имя пользователя"></input>
         <div className="passwordBox" ref={btnShowPassword}>
            <input type={props.password.type} className ="name" placeholder="Пароль"></input>
            <svg onClick={showPass()}></svg>
         </div>
         <a href="#" className="btn-type-1">Войти</a>
      </div>
   );
}
export default Autorization;
